    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"../generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nmodel User {\n  id             Int            @id @default(autoincrement())\n  name           String         @db.VarChar(255)\n  email          String         @unique @db.VarChar(255)\n  password       String\n  role           String         @db.VarChar(50) // \"admin\" | \"pensioner\"\n  pensioner_type PensionerType?\n  qr_token       String?        @unique @db.VarChar(255)\n  balance        Decimal        @default(0) @db.Decimal(10, 2)\n  first_login    Boolean        @default(true)\n  is_active      Boolean        @default(true)\n  created_at     DateTime       @default(now())\n  updated_at     DateTime       @updatedAt\n\n  orders       Order[]\n  sales        Sale[]\n  consumptions Consumption[]\n  movements    BalanceMovement[]\n\n  @@map(\"users\")\n}\n\n// ─── Enums ───────────────────────────────────────────────\n\nenum PensionerType {\n  ESTUDIANTE\n  TRABAJADOR\n}\n\nenum MealType {\n  DESAYUNO\n  ALMUERZO\n  CENA\n}\n\nenum Categoria {\n  ENTRADA\n  MENU\n}\n\n// ─── Productos ───────────────────────────────────────────\n\nmodel Producto {\n  id          Int       @id @default(autoincrement())\n  nombre      String\n  descripcion String?\n  precio      Decimal   @db.Decimal(10, 2)\n  imagen      String?\n  categoria   Categoria\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  menus      MenusProductos[]\n  orderItems OrderItem[]\n  saleItems  SaleItem[]\n\n  @@map(\"productos\")\n}\n\n// ─── Menus ───────────────────────────────────────────────\n\nmodel Menus {\n  id        String   @id @default(cuid())\n  nombre    String\n  activo    Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  productos MenusProductos[]\n\n  @@map(\"menus\")\n}\n\n// ─── MenusProductos (pivot) ──────────────────────────────\n\nmodel MenusProductos {\n  id         String   @id @default(cuid())\n  menuId     String\n  productoId Int\n  visible    Boolean  @default(true)\n  createdAt  DateTime @default(now())\n\n  menu     Menus    @relation(fields: [menuId], references: [id])\n  producto Producto @relation(fields: [productoId], references: [id], onDelete: Cascade)\n\n  @@unique([menuId, productoId])\n  @@map(\"menus_productos\")\n}\n\nenum OrderType {\n  MESA\n  PARA_LLEVAR\n}\n\nenum CustomerType {\n  REGULAR\n  PENSIONER\n}\n\nenum OrderStatus {\n  ACTIVE\n  CONFIRMED\n}\n\nenum PaymentMethod {\n  EFECTIVO\n  YAPE\n}\n\nmodel Order {\n  id           String       @id @default(cuid())\n  tableNumber  String?\n  type         OrderType\n  customerType CustomerType @default(REGULAR)\n  pensionerId  Int?\n  status       OrderStatus  @default(ACTIVE)\n  total        Decimal      @default(0) @db.Decimal(10, 2)\n  notes        String?\n  createdAt    DateTime     @default(now())\n  updatedAt    DateTime     @updatedAt\n\n  pensioner User?       @relation(fields: [pensionerId], references: [id])\n  items     OrderItem[]\n\n  @@index([status])\n  @@index([type])\n  @@index([pensionerId])\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id         String   @id @default(cuid())\n  orderId    String\n  productoId Int\n  quantity   Int\n  unitPrice  Decimal  @db.Decimal(10, 2)\n  subtotal   Decimal  @db.Decimal(10, 2)\n  isTakeaway Boolean  @default(false)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  order    Order    @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  producto Producto @relation(fields: [productoId], references: [id], onDelete: Cascade)\n\n  @@index([orderId])\n  @@index([productoId])\n  @@map(\"order_items\")\n}\n\nmodel Sale {\n  id            String       @id @default(cuid())\n  sourceOrderId String?      @unique\n  tableNumber   String?\n  type          OrderType\n  customerType  CustomerType @default(REGULAR)\n  pensionerId   Int?\n  customerLabel String?\n  total         Decimal      @db.Decimal(10, 2)\n  soldAt        DateTime     @default(now())\n  createdAt     DateTime     @default(now())\n  updatedAt     DateTime     @updatedAt\n\n  pensioner User?         @relation(fields: [pensionerId], references: [id])\n  items     SaleItem[]\n  payments  SalePayment[]\n\n  @@index([soldAt])\n  @@index([type])\n  @@index([pensionerId])\n  @@map(\"sales\")\n}\n\nmodel SaleItem {\n  id          String   @id @default(cuid())\n  saleId      String\n  productoId  Int?\n  productName String\n  quantity    Int\n  unitPrice   Decimal  @db.Decimal(10, 2)\n  subtotal    Decimal  @db.Decimal(10, 2)\n  isTakeaway  Boolean  @default(false)\n  createdAt   DateTime @default(now())\n\n  sale     Sale      @relation(fields: [saleId], references: [id], onDelete: Cascade)\n  producto Producto? @relation(fields: [productoId], references: [id], onDelete: SetNull)\n\n  @@index([saleId])\n  @@index([productoId])\n  @@map(\"sale_items\")\n}\n\nmodel SalePayment {\n  id        String        @id @default(cuid())\n  saleId    String\n  method    PaymentMethod\n  amount    Decimal       @db.Decimal(10, 2)\n  createdAt DateTime      @default(now())\n\n  sale Sale @relation(fields: [saleId], references: [id], onDelete: Cascade)\n\n  @@index([saleId])\n  @@index([method])\n  @@map(\"sale_payments\")\n}\n\n// ─── Consumos de Pensionistas ────────────────────────────\n\nmodel Consumption {\n  id        String   @id @default(cuid())\n  userId    Int\n  mealType  MealType\n  amount    Decimal  @db.Decimal(10, 2)\n  date      DateTime @default(now())\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n  @@index([date])\n  @@index([userId, date])\n  @@map(\"consumptions\")\n}\n\n// ─── Configuración de Precios (Trabajadores) ─────────────\n\nmodel PriceConfig {\n  id        String   @id @default(cuid())\n  mealType  MealType @unique\n  price     Decimal  @db.Decimal(10, 2)\n  updatedAt DateTime @updatedAt\n\n  @@map(\"price_config\")\n}\n\n// ─── Movimientos de Saldo ────────────────────────────────\n\nenum MovementType {\n  RECARGA\n  CONSUMO\n  AJUSTE\n}\n\nmodel BalanceMovement {\n  id          String       @id @default(cuid())\n  userId      Int\n  type        MovementType\n  amount      Decimal      @db.Decimal(10, 2)\n  balance     Decimal      @db.Decimal(10, 2) // saldo resultante después del movimiento\n  description String?\n  createdAt   DateTime     @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n\n  @@index([userId])\n  @@index([createdAt])\n  @@index([userId, createdAt])\n  @@map(\"balance_movements\")\n}\n",
